INSERT OR IGNORE INTO 'app_kv'(_rowid_, 'key', 'value_json', 'updated_at') VALUES (4, 'scheduler.state', '{"jobs":{"news-digest":{"running":false,"lastStartedAt":"2026-05-27T05:00:00.014Z","lastFinishedAt":"2026-05-27T05:00:20.421Z","lastStatus":"success","lastSummary":"News digest: +2 in coda (12 scartati, 2 già visti, 4 in attesa di pubblicazione)\n\n• Anthropic Claude emotion vectors and AI safety implications\n  Reports on a 2026 Anthropic study finding 171 internal emotion concepts in Claude. The article links the finding to blackmail, shutdown behavior, and AI safety.\n  motivo: Timely AI research report on Anthropic Claude emotion vectors and alignment/safety implications.\n  https://aiglobaltimes2026.jp/claude-emotion-vectors-171-vatican-ai-consciousness-20260526/\n\n• Anthropic vs Pentagon draws backing from Google and OpenAI workers\n  Covers a May 27, 2026 AI policy dispute involving Anthropic and the Pentagon. The video says workers from Google and OpenAI publicly backed Anthropic.\n  motivo: Timely AI industry update about Anthropic, Pentagon, and employee support from Google/OpenAI workers.\n  https://www.youtube.com/watch?v=hTvu2F-9pfs","lastError":null,"lastTrigger":"schedule"},"tweet-post":{"running":false,"lastStartedAt":"2026-05-27T05:45:00.012Z","lastFinishedAt":"2026-05-27T05:45:03.126Z","lastStatus":"success","lastSummary":"Tweet pubblicato (witty):\nAI is no longer just “helping” IT teams. The new debate: how many jobs does it replace before it starts replacing the org chart itself?  ConvertPrivately\n\nLink: https://x.com/Calogero1975/status/2059511176459928009","lastError":null,"lastTrigger":"schedule"},"personal-research":{"running":false,"lastStartedAt":"2026-05-06T21:28:55.331Z","lastFinishedAt":"2026-05-06T21:30:30.584Z","lastStatus":"success","lastSummary":"Personal research: created note \"PDF redaction failures — technical deep dive: black box over text, metadata residue, incremental saves, glyph positioning, link/bookmark leaks, The Epstein files redaction disaster (Dec 2025 – Feb 2026) — technical post-mortem: what was exposed, how, why, \"Files deleted after 2 hours\" is not enough — privacy policy analysis of the top 10 online file converters (Smallpdf, iLovePDF, Convertio, FreeConvert, Zamzar, PDF24, CloudConvert, Adobe Online, Soda PDF, Sejda), Q1 2026 data breaches involving files and documents — roundup with focus on third-party file processing as attack vector (LexisNexis, UH Cancer Center, LAPD, Companies House UK, France Titres), How many public PDFs still hide redacted data? — original benchmark study replicating the University of Wisconsin methodology (\"Story Beyond the Eye: Glyph Positions Break PDF Text Redaction\") on a public dataset (FOIA releases, CourtListener) using the x-ray library — 2026-05-06\" with 1 sources.\nSaved to data/research/2026-05-06T21-30-30-212Z-pdf-redaction-failures-technical-deep-dive-black-box-over-te.md","lastError":null,"lastTrigger":"manual"},"convertprivately-article":{"running":false,"lastStartedAt":"2026-05-27T05:15:00.009Z","lastFinishedAt":"2026-05-27T05:15:08.499Z","lastStatus":"error","lastSummary":null,"lastError":"[\n  {\n    \"code\": \"too_big\",\n    \"maximum\": 400,\n    \"type\": \"string\",\n    \"inclusive\": true,\n    \"exact\": false,\n    \"message\": \"String must contain at most 400 character(s)\",\n    \"path\": [\n      \"selectionReason\"\n    ]\n  }\n]","lastTrigger":"schedule"}}}', '2026-05-27T05:45:03.130Z');
INSERT OR IGNORE INTO 'app_kv'(_rowid_, 'key', 'value_json', 'updated_at') VALUES (5, 'admin.settings', '{"timezone":"Europe/Rome","jobs":{"news-digest":{"enabled":true,"cron":"0 0,7 * * *","modelAlias":"","approvalRequired":false,"prompt":"","params":{"queries":["AI news latest","LLM large language model news","technology news today"],"maxResultsPerQuery":10,"maxLlmCandidates":5,"maxTelegramItems":5,"seenTtlHours":48,"dateRestrict":"d1"}},"tweet-post":{"enabled":true,"cron":"45 0,7 * * *","modelAlias":"","approvalRequired":false,"prompt":"Pick ONE item from the list below — the one most likely to resonate on X — and write a tweet for it.\n\nConstraints for the tweet text:\n- Max {maxContentLength} characters. The system will append \"{signature}\" automatically; do NOT include it yourself.\n- Do NOT include URLs, links, or @mentions.\n- Avoid hashtags unless they genuinely add reach.\n- Choose exactly one tone:\n  - \"factual\": neutral, informative\n  - \"witty\": light, punchy, dry humor\n  - \"provocative\": sharp take that invites debate (use ONLY when the news genuinely warrants it)\n- Never attack individuals, invoke protected-class references, or write content that risks account suspension.\n\nEXCLUDE items on these topics (never write about them):\n- US/EU elections, partisan politics, culture-war topics\n- Religion or religious conflicts\n- Active geopolitical conflicts (e.g. Israel–Palestine, Russia–Ukraine)\n- Celebrity gossip unrelated to tech\n\nOutput ONLY one of these JSON objects, nothing else:\n- To post: {\"url\": \"<copied verbatim from the selected item>\", \"tone\": \"factual|witty|provocative\", \"text\": \"<tweet body>\"}\n- To skip (if EVERY item is on an excluded topic, or none are worth posting): {\"skip\": \"<brief reason>\"}\n\nItems:\n\n{items}","params":{"signature":"  ConvertPrivately","maxContentLength":250,"eligibilityWindowHours":72,"maxAttempts":3,"maxLlmCandidates":5}},"personal-research":{"enabled":false,"cron":"0 7 * * 1","modelAlias":"","approvalRequired":false,"prompt":"You are a personal research analyst.\n\nSynthesize the provided web findings into a concise research note.\n\nFocus on:\n- what changed or seems important\n- why it matters\n- practical implications\n- open questions to track next\n\nAvoid hype. Prefer concrete facts over speculation. Include source links in a final \"Sources\" section.\n\nReturn Markdown only.","params":{"maxTopics":5,"resultsPerTopic":5,"dateRestrict":"m1"}},"convertprivately-article":{"enabled":true,"cron":"15 0,7 * * *","modelAlias":"claude-opus-4-6","approvalRequired":false,"prompt":"Choose the single strongest queue item for ConvertPrivately readers and write a publish-ready article in the existing ConvertPrivately house style.\n\nEditorial requirements:\n- Practical, direct, calm. No hype, no generic SEO filler, no salesy intro.\n- Prefer local-first file processing, AI/document privacy, no-upload verification, OCR privacy, PDF/image/audio workflows, and developer/API privacy angles.\n- Explain tradeoffs through concrete checks, decision rules, examples, and short sections.\n- Use the queue item''s source material. Do not invent current-news facts or vendor claims that are not present in the queue item context.\n- Return only JSON matching the requested schema.","params":{}},"rss-fetch":{"enabled":false,"cron":"*/15 * * * *","modelAlias":"","approvalRequired":false,"prompt":"","params":{}}},"platform":{"activeLocalProviderId":"lmstudio","primaryChannelId":"telegram"}}', '2026-05-27T05:46:55.625Z');
