INSERT OR IGNORE INTO 'app_kv'(_rowid_, 'key', 'value_json', 'updated_at') VALUES (9, 'research.notes', '[{"id":"2026-05-06T21-30-30-212Z-pdf-redaction-failures-technical-deep-dive-black-box-over-te","title":"PDF redaction failures — technical deep dive: black box over text, metadata residue, incremental saves, glyph positioning, link/bookmark leaks, The Epstein files redaction disaster (Dec 2025 – Feb 2026) — technical post-mortem: what was exposed, how, why, \"Files deleted after 2 hours\" is not enough — privacy policy analysis of the top 10 online file converters (Smallpdf, iLovePDF, Convertio, FreeConvert, Zamzar, PDF24, CloudConvert, Adobe Online, Soda PDF, Sejda), Q1 2026 data breaches involving files and documents — roundup with focus on third-party file processing as attack vector (LexisNexis, UH Cancer Center, LAPD, Companies House UK, France Titres), How many public PDFs still hide redacted data? — original benchmark study replicating the University of Wisconsin methodology (\"Story Beyond the Eye: Glyph Positions Break PDF Text Redaction\") on a public dataset (FOIA releases, CourtListener) using the x-ray library — 2026-05-06","topics":["PDF redaction failures — technical deep dive: black box over text, metadata residue, incremental saves, glyph positioning, link/bookmark leaks","The Epstein files redaction disaster (Dec 2025 – Feb 2026) — technical post-mortem: what was exposed, how, why","\"Files deleted after 2 hours\" is not enough — privacy policy analysis of the top 10 online file converters (Smallpdf, iLovePDF, Convertio, FreeConvert, Zamzar, PDF24, CloudConvert, Adobe Online, Soda PDF, Sejda)","Q1 2026 data breaches involving files and documents — roundup with focus on third-party file processing as attack vector (LexisNexis, UH Cancer Center, LAPD, Companies House UK, France Titres)","How many public PDFs still hide redacted data? — original benchmark study replicating the University of Wisconsin methodology (\"Story Beyond the Eye: Glyph Positions Break PDF Text Redaction\") on a public dataset (FOIA releases, CourtListener) using the x-ray library"],"createdAt":"2026-05-06T21:30:30.212Z","filePath":"data/research/2026-05-06T21-30-30-212Z-pdf-redaction-failures-technical-deep-dive-black-box-over-te.md","sourceCount":1}]', '2026-05-06T21:30:30.216Z');
